import './productos.css';
import data from "./data-json/data.json";
import Tarjeta from './tarjetas-simple-doble/tarjeta';

function Productos() {
  return (
    <div className="productos">
      {data && data.map((elemento) => (
        <Tarjeta key={elemento.id} titulo={elemento.titulo} ruta={elemento.ruta} precio={elemento.precio} />
      ))}
    </div>
  );
}

export default Productos;
